mapper.select:
SELECT p.id, p.title, p.summary, p.cover_image AS coverImage, p.author_id AS authorId, u.username AS authorName, p.category_id AS categoryId, c.name AS categoryName, p.status, p.is_top AS isTop, p.view_count AS viewCount, p.like_count AS likeCount, p.comment_count AS commentCount, p.create_time AS createTime, p.update_time AS updateTime, p.publish_time AS publishTime FROM blog_post p LEFT JOIN sys_user u ON p.author_id = u.id LEFT JOIN blog_category c ON p.category_id = c.id
AND p.title LIKE CONCAT('%', #{title}, '%')
AND p.category_id = #{categoryId}
AND p.status = #{status}
AND p.author_id = #{authorId}
ORDER BY p.is_top DESC, p.create_time DESC
